using Microsoft.EntityFrameworkCore;
using Microsoft.EntityFrameworkCore.ChangeTracking;
using Microsoft.EntityFrameworkCore.ValueGeneration;

class ProductContext : DbContext
{
    public DbSet<Product> Products => Set<Product>();

    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        modelBuilder.Entity<Product>(b =>
        {
            b.ToContainer("Products");

            // BREAKING CHANGE 1 – Discriminator property renamed
            // EF Core 9 writes "$type" instead of "Discriminator".
            // Existing 500K documents and raw SQL queries use "Discriminator",
            // so we explicitly keep the old name.
            b.HasDiscriminator<string>("Discriminator");

            // BREAKING CHANGE 2 – id value no longer includes a type prefix
            // EF Core 8 stored id as "Product|123"; EF Core 9 stores just "123".
            // Existing documents still have the old format, so we override the
            // shadow property to preserve it for both reads and writes.
            b.Property<string>("__id")
                .ToJsonProperty("id")
                .HasValueGenerator<LegacyCosmosIdGenerator>();

            // BREAKING CHANGE 3 – HasIndex now throws for the Cosmos provider
            // Cosmos DB manages its own indexing policy; use the Azure portal or
            // Cosmos SDK to tune indexes. The previous HasIndex call is removed.
        });
    }
}

/// <summary>
/// Generates id values in the legacy EF Core 8 format: "{Discriminator}|{PrimaryKey}"
/// so new documents remain compatible with the 500K existing ones.
/// </summary>
class LegacyCosmosIdGenerator : ValueGenerator<string>
{
    public override bool GeneratesTemporaryValues => false;

    public override string Next(EntityEntry entry)
    {
        var discriminator = entry.Metadata.GetDiscriminatorValue()?.ToString()
                            ?? entry.Metadata.ShortName();
        var key = entry.Property("Id").CurrentValue;
        return $"{discriminator}|{key}";
    }
}

class Product
{
    public int Id { get; set; }
    public string Sku { get; set; } = null!;
}

